class PaymentGatewayFactory {
  static PaymentGateway create(PaymentMethodType type) {
    switch (type) {
      case PaymentMethodType.inAppPurchase:
        return InAppPurchaseGateway();
      case PaymentMethodType.applePay:
        return ApplePayGateway();
      case PaymentMethodType.googlePay:
        return GooglePayGateway();
      case PaymentMethodType.mobileWallet:
        return Platform.isIOS ? ApplePayGateway() : GooglePayGateway();
      case PaymentMethodType.card:
      case PaymentMethodType.unknown:
        return InAppPurchaseGateway();
    }
  }
}

class PaymentController extends ChangeNotifier {
  PaymentService? _service;
  PaymentStatus _status = PaymentStatus.idle;
  PaymentResult? _lastResult;
  bool _isBusy = false;

  PaymentStatus get status => _status;
  PaymentResult? get lastResult => _lastResult;
  bool get isBusy => _isBusy;

  Future<void> configure({
    required PaymentMethodType paymentMethod,
    PaymentTelemetry? telemetry,
    SecureStorageAdapter? storage,
  }) async {
    final gateway = PaymentGatewayFactory.create(paymentMethod);
    _service = PaymentService(
      gateway: gateway,
      storage: storage,
      telemetry: telemetry,
    );
    await _service!.init();
    _status = PaymentStatus.idle;
    notifyListeners();
  }

  Future<PaymentResult> startPayment(PaymentRequest request) async {
    if (_service == null) {
      throw PaymentException('payment_service_not_configured', 'Payment service is not configured');
    }
    _isBusy = true;
    _status = PaymentStatus.processing;
    notifyListeners();

    try {
      final result = await _service!.processPayment(request);
      _lastResult = result;
      _status = result.status;
      return result;
    } finally {
      _isBusy = false;
      notifyListeners();
    }
  }

  Future<PaymentResult> restorePurchases() async {
    if (_service == null) {
      throw PaymentException('payment_service_not_configured', 'Payment service is not configured');
    }
    _isBusy = true;
    _status = PaymentStatus.processing;
    notifyListeners();

    try {
      final result = await _service!.restore();
      _lastResult = result;
      _status = result.status;
      return result;
    } finally {
      _isBusy = false;
      notifyListeners();
    }
  }

  Future<PaymentResult> verifyToken(String token) async {
    if (_service == null) {
      throw PaymentException('payment_service_not_configured', 'Payment service is not configured');
    }
    final result = await _service!.verify(token);
    _lastResult = result;
    _status = result.status;
    notifyListeners();
    return result;
  }

  Future<void> disposeController() async {
    await _service?.dispose();
    _service = null;
    _status = PaymentStatus.idle;
    _lastResult = null;
    _isBusy = false;
    notifyListeners();
  }
}

