class PaymentSecurity {
  static String redact(String input) {
    if (input.isEmpty) return input;
    if (input.length <= 6) return '***';
    return '${input.substring(0, 3)}***${input.substring(input.length - 3)}';
  }

  static Map<String, dynamic> sanitize(Map<String, dynamic> data, {bool redactValues = true}) {
    const sensitiveKeys = {
      'cardNumber',
      'pan',
      'cvv',
      'cvc',
      'securityCode',
      'token',
      'receipt',
      'password',
      'secret',
      'auth',
      'authorization',
    };

    final result = <String, dynamic>{};
    for (final entry in data.entries) {
      final key = entry.key;
      final value = entry.value;
      if (sensitiveKeys.contains(key.toLowerCase())) {
        result[key] = redactValues ? '***REDACTED***' : value;
      } else if (value is Map<String, dynamic>) {
        result[key] = sanitize(value, redactValues: redactValues);
      } else if (value is List) {
        result[key] = value
            .map((e) => e is Map<String, dynamic> ? sanitize(e, redactValues: redactValues) : e)
            .toList();
      } else {
        result[key] = value;
      }
    }
    return result;
  }
}